-- ============================================================
-- Nairobi Open: SAMPLE TOURNAMENT DATA (generated from the app's
-- mock data builder; do not edit by hand).
--
-- Run AFTER supabase-schema.sql, in the same (dispatch) project.
-- Safe to re-run: it resets all entrants and matches back to this
-- sample state. Events, the tournament row, and the admin PIN are
-- kept as they are.
--
-- What it seeds: Open Doubles (Men) with 50 teams and its group
-- stage fully played (ready to test "Confirm group stage finished"
-- and the knockout); Open Singles (Women) mid-tournament holding all
-- four courts (shared pool: doubles has nothing queued) with one
-- postponed match; small 8-entrant fields in the other 11 events.
-- Real rosters later: Admin tab -> "Start over with a new list" per
-- event replaces that event's sample data.
--
-- To wipe ALL sample data instead (keep events + PIN), run:
--   -- delete from nairobi_matches;
--   -- delete from nairobi_entrants;
--   -- update nairobi_events set active = false, stage = 'group';
-- ============================================================

-- Guard: the 13 seeded events must exist (run supabase-schema.sql first).
do $$
declare
  missing text;
begin
  select string_agg(v.name, ', ') into missing
  from (values ('Open Doubles (Men)'), ('Open Singles (Women)'), ('Open Singles (Men)'), ('Open Doubles (Women)'), ('Open Mixed Doubles'), ('Intermediate Singles (Men)'), ('Intermediate Singles (Women)'), ('Intermediate Doubles (Men)'), ('Intermediate Doubles (Women)'), ('Intermediate Mixed Doubles'), ('Masters Doubles (Men)'), ('Masters Doubles (Women)'), ('Masters Mixed Doubles')) as v(name)
  where not exists (select 1 from nairobi_events e where e.name = v.name);
  if missing is not null then
    raise exception 'Missing events: %. Run supabase-schema.sql first (or event names were edited).', missing;
  end if;
end $$;

-- Reset to a clean sample state.
delete from nairobi_matches;
delete from nairobi_entrants;

-- Event configuration (courts, formats, schedule notes, running state).
update nairobi_events set active = true, stage = 'group', settings = '{"points_to_group":21,"points_to_knockout":21,"best_of_group":1,"best_of_knockout":1,"advance_per_group":2,"knockout_size":"auto","group_size":6,"schedule_note":"Day 1"}'::jsonb where name = 'Open Doubles (Men)';
update nairobi_events set active = true, stage = 'group', settings = '{"points_to_group":21,"points_to_knockout":21,"best_of_group":1,"best_of_knockout":3,"advance_per_group":2,"knockout_size":"auto","group_size":5,"schedule_note":"Day 1"}'::jsonb where name = 'Open Singles (Women)';
update nairobi_events set active = false, stage = 'group', settings = '{"points_to_group":21,"points_to_knockout":21,"best_of_group":1,"best_of_knockout":1,"advance_per_group":2,"knockout_size":"auto","group_size":4,"schedule_note":"Day 2"}'::jsonb where name = 'Open Singles (Men)';
