update nairobi_events set active = false, stage = 'group', settings = '{"points_to_group":21,"points_to_knockout":21,"best_of_group":1,"best_of_knockout":1,"advance_per_group":2,"knockout_size":"auto","group_size":4,"schedule_note":"Day 2"}'::jsonb where name = 'Open Mixed Doubles';
update nairobi_events set active = false, stage = 'group', settings = '{"points_to_group":21,"points_to_knockout":21,"best_of_group":1,"best_of_knockout":1,"advance_per_group":2,"knockout_size":"auto","group_size":4,"schedule_note":"Day 3"}'::jsonb where name = 'Intermediate Singles (Men)';
