update nairobi_events set active = false, stage = 'group', settings = '{"points_to_group":21,"points_to_knockout":21,"best_of_group":1,"best_of_knockout":1,"advance_per_group":2,"knockout_size":"auto","group_size":4,"schedule_note":"Day 4"}'::jsonb where name = 'Masters Mixed Doubles';

-- Entrants.

-- Matches (called_at = now() for on-court matches so banners show).

-- Sanity check: expect 153 entrants, 294 matches,
-- and all 132 of the men's doubles group matches played.
select
  (select count(*) from nairobi_entrants) as entrants,
  (select count(*) from nairobi_matches) as matches,
  (select count(*) from nairobi_matches m
     where m.event_id = (select id from nairobi_events where name = 'Open Doubles (Men)') and m.status = 'played') as mens_doubles_played;
